\begin{aligned}
                {x^{2}-2x-16}= 19\amp \Rightarrow {x^{2}-2x-35}= 0 \\
                                    \amp \Rightarrow (x+5)(x - 7) = 0 \\
                                    \amp  \Rightarrow x+5=0 \text{ or } x - 7=0\\
                                    \amp  \Rightarrow x=-5\text{ or } x=7\\
